import{c as e,S as t,j as n,m as a}from"./chunks/framework.BRZzRcmb.js";const c=JSON.parse('{"title":"Andes virus — joint estimation of incubation, transmission timing, and R(t)","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":null}'),o={name:"index.md"};function s(r,i,d,l,u,p){return t(),n("div",null,[...i[0]||(i[0]=[a('<h1 id="Andes-virus-—-joint-estimation-of-incubation,-transmission-timing,-and-Rt" tabindex="-1">Andes virus — joint estimation of incubation, transmission timing, and R(t) <a class="header-anchor" href="#Andes-virus-—-joint-estimation-of-incubation,-transmission-timing,-and-Rt" aria-label="Permalink to &quot;Andes virus — joint estimation of incubation, transmission timing, and R(t) {#Andes-virus-—-joint-estimation-of-incubation,-transmission-timing,-and-Rt}&quot;">​</a></h1><p>A Julia + Turing model fitted to the Epuyén 2018–19 Andes hantavirus outbreak (<a href="https://doi.org/10.1056/NEJMoa2009040" target="_blank" rel="noreferrer">Martínez et al. 2020, NEJM</a>).</p><p>Four quantities are estimated jointly from the line list: the incubation period, the transmission timing of each secondary infection relative to its source&#39;s symptom onset, a weekly time-varying reproduction number, and offspring dispersion. Exposure and onset dates are interval-censored. Each case is given a continuous latent infection time and a continuous latent onset time, each sampled within its recorded window. Generation interval and serial interval are derived from the fitted distributions in post-processing.</p><h2 id="Pages" tabindex="-1">Pages <a class="header-anchor" href="#Pages" aria-label="Permalink to &quot;Pages {#Pages}&quot;">​</a></h2><ul><li><p><a href="./model">Model</a> — priors, data augmentation, GI / SI derivation.</p></li><li><p><a href="./limitations">Limitations</a> — known caveats around exposure encoding, late R(t) bins, dispersion identifiability, and right-truncation.</p></li><li><p><a href="./analysis">Analysis walkthrough</a> — runs the full analysis end to end.</p></li><li><p><a href="./api">API Reference</a> — exported functions.</p></li></ul><h2 id="Citing" tabindex="-1">Citing <a class="header-anchor" href="#Citing" aria-label="Permalink to &quot;Citing {#Citing}&quot;">​</a></h2><blockquote><p>Martínez VP, Di Paola N, Alonso DO, et al. <em>&quot;Super-spreaders&quot; and person-to-person transmission of Andes virus in Argentina.</em> N Engl J Med 2020;383:2230–41. <a href="https://doi.org/10.1056/NEJMoa2009040" target="_blank" rel="noreferrer">doi:10.1056/NEJMoa2009040</a></p></blockquote><p>The reporting follows:</p><blockquote><p>Charniga K, et al. <em>Best practices for estimating and reporting epidemiological delay distributions of infectious diseases.</em> 2024. <a href="https://arxiv.org/abs/2405.08841" target="_blank" rel="noreferrer">arXiv:2405.08841</a></p></blockquote>',9)])])}const f=e(o,[["render",s]]);export{c as __pageData,f as default};
